class LogConfig:
    """Configuration for the logging utility."""
    
    def __init__(
        self,
        log_dir="logs",
        log_file="app.log",
        host="0.0.0.0",
        port=8080,
        max_file_size_mb=50,
        enable_console_output=True,
        log_rotation=True,
        max_backup_files=5
    ):
        self.log_dir = log_dir
        self.log_file = log_file
        self.host = host
        self.port = port
        self.max_file_size_bytes = max_file_size_mb * 1024 * 1024
        self.enable_console_output = enable_console_output
        self.log_rotation = log_rotation
        self.max_backup_files = max_backup_files


class LogWriter:
    """Handles writing log messages to file with rotation support."""
    
    LEVELS = {
        "DEBUG": 10,
        "INFO": 20,
        "WARNING": 30,
        "ERROR": 40,
        "CRITICAL": 50
    }
    
    LOG_FORMAT = "[{timestamp}] [{level}] [{service}] [{request_id}] {message}\n"
    
    def __init__(self, config):
        self.config = config
        self.lock = threading.Lock()
        self._ensure_log_directory()
        self.log_file_path = os.path.join(config.log_dir, config.log_file)
        self._open_file()
    
    def _ensure_log_directory(self):
        os.makedirs(self.config.log_dir, exist_ok=True)
    
    def _open_file(self):
        self.file_handle = open(self.log_file_path, "a", encoding="utf-8")
    
    def _rotate_if_needed(self):
        if not self.config.log_rotation:
            return
        
        try:
            current_size = os.path.getsize(self.log_file_path)
        except OSError:
            current_size = 0
        
        if current_size >= self.config.max_file_size_bytes:
            self.file_handle.close()
            
            # Rotate existing backup files
            for i in range(self.config.max_backup_files - 1, 0, -1):
                src = "%s.%d" % (self.log_file_path, i)
                dst = "%s.%d" % (self.log_file_path, i + 1)
                if os.path.exists(src):
                    if os.path.exists(dst):
                        os.remove(dst)
                    os.rename(src, dst)
            
            # Rename current log to .1
            backup_path = "%s.1" % self.log_file_path
            if os.path.exists(backup_path):
                os.remove(backup_path)
            os.rename(self.log_file_path, backup_path)
            
            self._open_file()
    
    def write_log(self, level, service, message, request_id="N/A", metadata=None):
        level = level.upper()
        if level not in self.LEVELS:
            level = "INFO"
        
        timestamp = datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S.%f")[:-3]
        
        log_entry = self.LOG_FORMAT.format(
            timestamp=timestamp,
            level="%-8s" % level,
            service=service,
            request_id=request_id,
            message=message
        )
        
        # Append metadata if present
        if metadata:
            metadata_str = "  | metadata: %s\n" % json.dumps(metadata)
            log_entry = log_entry.rstrip("\n") + metadata_str
        
        with self.lock:
            self._rotate_if_needed()
            self.file_handle.write(log_entry)
            self.file_handle.flush()
            
            if self.config.enable_console_output:
                sys.stdout.write(log_entry)
                sys.stdout.flush()
        
        return log_entry.strip()
    
    def close(self):
        with self.lock:
            if self.file_handle and not self.file_handle.closed:
                self.file_handle.close()
    
    def query_logs(self, service=None, level=None, start_time=None, end_time=None, limit=100):
        """Query logs from file with optional filters."""
        results = []
        
        try:
            with open(self.log_file_path, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    
                    if service and ("[%s]" % service) not in line:
                        continue
                    
                    if level and ("[%s" % level.upper()) not in line:
                        continue
                    
                    if start_time:
                        try:
                            log_ts = line.split("]")[0].lstrip("[")
                            if log_ts < start_time:
                                continue
                        except (IndexError, ValueError):
                            continue
                    
                    if end_time:
                        try:
                            log_ts = line.split("]")[0].lstrip("[")
                            if log_ts > end_time:
                                continue
                        except (IndexError, ValueError):
                            continue
                    
                    results.append(line)
                    
                    if len(results) >= limit:
                        break
        except FileNotFoundError:
            pass
        
        return results


class LogRequestHandler(http.server.BaseHTTPRequestHandler):
    """HTTP request handler for log ingestion and querying."""
    
    log_writer = None
    
    def log_message(self, format, *args):
        # Suppress default HTTP server logging to avoid noise
        pass
    
    def _send_json_response(self, status_code, data):
        response = json.dumps(data, indent=2)
        self.send_response(status_code)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", str(len(response.encode("utf-8"))))
        self.end_headers()
        self.wfile.write(response.encode("utf-8"))
    
    def _read_body(self):
        content_length = int(self.headers.get("Content-Length", 0))
        if content_length == 0:
            return None
        body = self.rfile.read(content_length)
        return json.loads(body.decode("utf-8"))
    
    def do_POST(self):
        parsed_path = urlparse(self.path)
        
        if parsed_path.path == "/log":
            self._handle_single_log()
        elif parsed_path.path == "/log/batch":
            self._handle_batch_log()
        elif parsed_path.path == "/log/query":
            self._handle_query_logs()
        else:
            self._send_json_response(404, {
                "error": "Not found",
                "available_endpoints": {
                    "POST /log": "Submit a single log entry",
                    "POST /log/batch": "Submit multiple log entries",
                    "POST /log/query": "Query log entries",
                    "GET /health": "Health check",
                    "GET /stats": "Log statistics"
                }
            })
    
    def do_GET(self):
        parsed_path = urlparse(self.path)
        
        if parsed_path.path == "/health":
            self._handle_health_check()
        elif parsed_path.path == "/stats":
            self._handle_stats()
        elif parsed_path.path == "/logs":
            self._handle_get_logs(parsed_path)
        else:
            self._send_json_response(404, {"error": "Not found"})
    
    def _handle_single_log(self):
        try:
            data = self._read_body()
            if not data:
                self._send_json_response(400, {"error": "Empty request body"})
                return
            
            # Validate required fields
            required_fields = ["service", "message"]
            missing = [f for f in required_fields if f not in data]
            if missing:
                self._send_json_response(400, {
                    "error": "Missing required fields: %s" % ", ".join(missing)
                })
                return
            
            service = data["service"]
            message = data["message"]
            level = data.get("level", "INFO")
            request_id = data.get("request_id", "N/A")
            metadata = data.get("metadata", None)
            
            # Sanitize inputs
            service = self._sanitize_input(service)
            message = self._sanitize_input(message)
            
            log_entry = self.log_writer.write_log(
                level=level,
                service=service,
                message=message,
                request_id=request_id,
                metadata=metadata
            )
            
            self._send_json_response(201, {
                "status": "logged",
                "entry": log_entry
            })
        
        except json.JSONDecodeError:
            self._send_json_response(400, {"error": "Invalid JSON in request body"})
        except Exception as e:
            self._send_json_response(500, {"error": "Internal error: %s" % str(e)})
    
    def _handle_batch_log(self):
        try:
            data = self._read_body()
            if not data:
                self._send_json_response(400, {"error": "Empty request body"})
                return
            
            if not isinstance(data, dict) or "logs" not in data:
                self._send_json_response(400, {
                    "error": "Request body must contain a 'logs' array"
                })
                return
            
            logs = data["logs"]
            if not isinstance(logs, list):
                self._send_json_response(400, {"error": "'logs' must be an array"})
                return
            
            results = []
            errors = []
            
            for i, log_entry in enumerate(logs):
                try:
                    if "service" not in log_entry or "message" not in log_entry:
                        errors.append({
                            "index": i,
                            "error": "Missing 'service' or 'message'"
                        })
                        continue
                    
                    service = self._sanitize_input(log_entry["service"])
                    message = self._sanitize_input(log_entry["message"])
                    level = log_entry.get("level", "INFO")
                    request_id = log_entry.get("request_id", "N/A")
                    metadata = log_entry.get("metadata", None)
                    
                    entry = self.log_writer.write_log(
                        level=level,
                        service=service,
                        message=message,
                        request_id=request_id,
                        metadata=metadata
                    )
                    results.append({"index": i, "status": "logged"})
                
                except Exception as e:
                    errors.append({"index": i, "error": str(e)})
            
            self._send_json_response(201, {
                "status": "batch_processed",
                "total": len(logs),
                "logged": len(results),
                "failed": len(errors),
                "errors": errors if errors else None
            })
        
        except json.JSONDecodeError:
            self._send_json_response(400, {"error": "Invalid JSON in request body"})
        except Exception as e:
            self._send_json_response(500, {"error": "Internal error: %s" % str(e)})
    
    def _handle_query_logs(self):
        try:
            data = self._read_body()
            if not data:
                data = {}
            
            service = data.get("service")
            level = data.get("level")
            start_time = data.get("start_time")
            end_time = data.get("end_time")
            limit = data.get("limit", 100)
            
            results = self.log_writer.query_logs(
                service=service,
                level=level,
                start_time=start_time,
                end_time=end_time,
                limit=limit
            )
            
            self._send_json_response(200, {
                "count": len(results),
                "logs": results
            })
        
        except Exception as e:
            self._send_json_response(500, {"error": "Query error: %s" % str(e)})
    
    def _handle_get_logs(self, parsed_path):
        try:
            params = parse_qs(parsed_path.query)
            service = params.get("service", [None])[0]
            level = params.get("level", [None])[0]
            limit = int(params.get("limit", [100])[0])
            
            results = self.log_writer.query_logs(
                service=service,
                level=level,
                limit=limit
            )
            
            self._send_json_response(200, {
                "count": len(results),
                "logs": results
            })
        
        except Exception as e:
            self._send_json_response(500, {"error": "Query error: %s" % str(e)})
    
    def _handle_health_check(self):
        self._send_json_response(200, {
            "status": "healthy",
            "timestamp": datetime.utcnow().isoformat(),
            "log_file": self.log_writer.log_file_path,
            "log_file_exists": os.path.exists(self.log_writer.log_file_path)
        })
    
    def _handle_stats(self):
        try:
            log_file = self.log_writer.log_file_path
            file_size = 0
            line_count = 0
            services = set()
            level_counts = {"DEBUG": 0, "INFO": 0, "WARNING": 0, "ERROR": 0, "CRITICAL": 0}
            
            if os.path.exists(log_file):
                file_size = os.path.getsize(log_file)
                
                with open(log_file, "r", encoding="utf-8") as f:
                    for line in f:
                        line = line.strip()
                        if not line:
                            continue
                        line_count += 1
                        
                        # Extract service name
                        try:
                            parts = line.split("]")
                            if len(parts) >= 3:
                                service_name = parts[2].strip().lstrip("[")
                                services.add(service_name)
                            if len(parts) >= 2:
                                level_name = parts[1].strip().lstrip("[").strip()
                                if level_name in level_counts:
                                    level_counts[level_name] += 1
                        except (IndexError, ValueError):
                            pass
            
            # Count backup files
            backup_count = 0
            for i in range(1, self.log_writer.config.max_backup_files + 1):
                if os.path.exists("%s.%d" % (log_file, i)):
                    backup_count += 1
            
            self._send_json_response(200, {
                "log_file": log_file,
                "file_size_bytes": file_size,
                "file_size_readable": self._format_size(file_size),
                "total_entries": line_count,
                "unique_services": sorted(list(services)),
                "service_count": len(services),
                "level_counts": level_counts,
                "backup_files": backup_count,
                "max_file_size": self._format_size(self.log_writer.config.max_file_size_bytes)
            })
        
        except Exception as e:
            self._send_json_response(500, {"error": "Stats error: %s" % str(e)})
    
    @staticmethod
    def _sanitize_input(value):
        if not isinstance(value, str):
            value = str(value)
        # Remove newlines to prevent log injection
        value = value.replace("\n", " ").replace("\r", " ")
        return value
    
    @staticmethod
    def _format_size(size_bytes):
        if size_bytes < 1024:
            return "%d B" % size_bytes
        elif size_bytes < 1024 * 1024:
            return "%.2f KB" % (size_bytes / 1024)
        elif size_bytes < 1024 * 1024 * 1024:
            return "%.2f MB" % (size_bytes / (1024 * 1024))
        else:
            return "%.2f GB" % (size_bytes / (1024 * 1024 * 1024))


class CentralLogServer:
    """Main server class for centralized logging."""
    
    def __init__(self, config=None):
        self.config = config or LogConfig()
        self.log_writer = LogWriter(self.config)
        self.server = None
    
    def start(self):
        LogRequestHandler.log_writer = self.log_writer
        
        self.server = http.server.HTTPServer(
            (self.config.host, self.config.port),
            LogRequestHandler
        )
        
        startup_msg = (
            "\n"
            "========================================\n"
            "  Centralized Log Server Started\n"
            "========================================\n"
            "  Host:     %s\n"
            "  Port:     %d\n"
            "  Log File: %s\n"
            "  Log Dir:  %s\n"
            "========================================\n"
            "\n"
            "  Endpoints:\n"
            "    POST /log        - Submit single log\n"
            "    POST /log/batch  - Submit batch logs\n"
            "    POST /log/query  - Query logs\n"
            "    GET  /logs       - Get logs (with query params)\n"
            "    GET  /health     - Health check\n"
            "    GET  /stats      - Log statistics\n"
            "========================================\n"
        ) % (
            self.config.host,
            self.config.port,
            os.path.join(self.config.log_dir, self.config.log_file),
            os.path.abspath(self.config.log_dir)
        )
        
        print(startup_msg)
        
        self.log_writer.write_log(
            level="INFO",
            service="log-server",
            message="Centralized log server started on %s:%d" % (
                self.config.host, self.config.port
            )
        )
        
        try:
            self.server.serve_forever()
        except KeyboardInterrupt:
            print("\nShutting down log server...")
            self.stop()
    
    def stop(self):
        if self.server:
            self.log_writer.write_log(
                level="INFO",
                service="log-server",
                message="Log server shutting down"
            )
            self.server.shutdown()
            self.log_writer.close()
            print("Log server stopped.")
    
    def start_background(self):
        """Start the server in a background thread."""
        LogRequestHandler.log_writer = self.log_writer
        
        self.server = http.server.HTTPServer(
            (self.config.host, self.config.port),
            LogRequestHandler
        )
        
        thread = threading.Thread(target=self.server.serve_forever, daemon=True)
        thread.start()
        
        self.log_writer.write_log(
            level="INFO",
            service="log-server",
            message="Centralized log server started in background on %s:%d" % (
                self.config.host, self.config.port
            )
        )
        
        return thread


class LogClient:
    """Simple client for sending logs to the centralized log server."""
    
    def __init__(self, server_url="http://localhost:8080", service_name="default"):
        self.server_url = server_url.rstrip("/")
        self.service_name = service_name
    
    def _send_request(self, path, data):
        import urllib.request
        
        url = "%s%s" % (self.server_url, path)
        json_data = json.dumps(data).encode("utf-8")
        
        req = urllib.request.Request(
            url,
            data=json_data,
            headers={"Content-Type": "application/json"},
            method="POST"
        )
        
        try:
            with urllib.request.urlopen(req, timeout=5) as response:
                return json.loads(response.read().decode("utf-8"))
        except Exception as e:
            return {"error": "Failed to send log: %s" % str(e)}
    
    def log(self, level, message, request_id="N/A", metadata=None):
        data = {
            "service": self.service_name,
            "level": level,
            "message": message,
            "request_id": request_id
        }
        if metadata:
            data["metadata"] = metadata
        return self._send_request("/log", data)
    
    def debug(self, message, **kwargs):
        return self.log("DEBUG", message, **kwargs)
    
    def info(self, message, **kwargs):
        return self.log("INFO", message, **kwargs)
    
    def warning(self, message, **kwargs):
        return self.log("WARNING", message, **kwargs)
    
    def error(self, message, **kwargs):
        return self.log("ERROR", message, **kwargs)
    
    def critical(self, message, **kwargs):
        return self.log("CRITICAL", message, **kwargs)
    
    def batch_log(self, log_entries):
        """Send multiple log entries at once.
        
        Each entry should be a dict with at least 'message' and optionally
        'level', 'request_id', 'metadata'.
        """
        logs = []
        for entry in log_entries:
            log_data = {
                "service": self.service_name,
                "level": entry.get("level", "INFO"),
                "message": entry["message"],
                "request_id": entry.get("request_id", "N/A")
            }
            if "metadata" in entry:
                log_data["metadata"] = entry["metadata"]
            logs.append(log_data)
        
        return self._send_request("/log/batch", {"logs": logs})
    
    def query(self, service=None, level=None, start_time=None, end_time=None, limit=100):
        data = {"limit": limit}
        if service:
            data["service"] = service
        if level:
            data["level"] = level
        if start_time:
            data["start_time"] = start_time
        if end_time:
            data["end_time"] = end_time
        return self._send_request("/log/query", data)


def demo():
    """Run a demo showing both server and client usage."""
    import time
    
    config = LogConfig(
        log_dir="logs",
        log_file="centralized.log",
        port=8080,
        enable_console_output=True,
        max_file_size_mb=10
    )
    
    server = CentralLogServer(config)
    server.start_background()
    
    # Give server time to start
    time.sleep(0.5)
    
    # Create clients for different microservices
    auth_client = LogClient(service_name="auth-service")
    api_client = LogClient(service_name="api-gateway")
    user_client = LogClient(service_name="user-service")
    payment_client = LogClient(service_name="payment-service")
    
    print("\n--- Sending sample log messages ---\n")
    
    # Single log entries
    auth_client.info("User login attempt", request_id="req-001")
    auth_client.info(
        "User authenticated successfully",
        request_id="req-001",
        metadata={"user_id": "usr-12345", "method": "oauth2"}
    )
    
    api_client.debug("Routing request to user-service", request_id="req-002")
    api_client.warning(
        "Rate limit approaching for client",
        request_id="req-003",
        metadata={"client_ip": "192.168.1.100", "requests_per_min": 95}
    )
    
    user_client.info("Fetching user profile", request_id="req-002")
    user_client.error(
        "Database connection timeout",
        request_id="req-004",
        metadata={"db_host": "db-primary", "timeout_ms": 5000}
    )
    
    payment_client.critical(
        "Payment gateway unreachable",
        request_id="req-005",
        metadata={"gateway": "stripe", "retry_count": 3}
    )
    
    # Batch log entries
    api_client.batch_log([
        {"level": "INFO", "message": "Request received: GET /api/users", "request_id": "req-006"},
        {"level": "INFO", "message": "Request received: POST /api/orders", "request_id": "req-007"},
        {"level": "DEBUG", "message": "Cache hit for user profile", "request_id": "req-006"},
        {"level": "WARNING", "message": "Slow query detected: 2.3s", "request_id": "req-007",
         "metadata": {"query": "SELECT * FROM orders WHERE...", "duration_ms": 2300}},
    ])
    
    time.sleep(0.5)
    
    # Query logs
    print("\n--- Querying logs ---\n")
    
    result = auth_client.query(service="auth-service")
    print("Auth service logs: %d entries found" % result.get("count", 0))
    for log in result.get("logs", []):
        print("  %s" % log)
    
    print()
    result = api_client.query(level="WARNING")
    print("WARNING level logs: %d entries found" % result.get("count", 0))
    for log in result.get("logs", []):
        print("  %s" % log)
    
    # Get stats
    print("\n--- Server Stats ---\n")
    import urllib.request
    try:
        with urllib.request.urlopen("http://localhost:8080/stats") as resp:
            stats = json.loads(resp.read().decode("utf-8"))
            print(json.dumps(stats, indent=2))
    except Exception as e:
        print("Error fetching stats: %s" % e)
    
    print("\n--- Demo complete ---")
    print("Log file location: %s" % os.path.abspath(
        os.path.join(config.log_dir, config.log_file)
    ))
    
    server.stop()


